package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;
import org.mockito.Mock;
import org.mockito.Mockito;
import java.io.IOException;

public class CSVFormatTest {

    @Mock
    private Appendable appendable;

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrintWithNullObject() throws IOException {
        csvFormat.print(null, "value", 0, 5, appendable, true);
        Mockito.verify(appendable).append("value");
    }

    @Test
    public void testPrintWithQuoteCharacterSet() throws IOException {
        Object object = "test";
        csvFormat.print(object, "value", 0, 5, appendable, true);
        Mockito.verify(appendable).append("\"value\"");
    }

    @Test
    public void testPrintWithEscapeCharacterSet() throws IOException {
        csvFormat = CSVFormat.DEFAULT.withEscape('"');
        csvFormat.print(null, "value", 0, 5, appendable, true);
        Mockito.verify(appendable).append("value");
    }

    @Test
    public void testPrintWithoutNewRecord() throws IOException {
        csvFormat.print(null, "value", 0, 5, appendable, false);
        Mockito.verify(appendable).append(",");
    }
}
